<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">QuickBooks Online</h1><p class="text-muted mb-0">OAuth connection and synchronization queue for invoices, customers, and payments.</p></div><span class="badge text-bg-<?=$connection['status']==='connected'?'success':'secondary'?> fs-6"><?=e($connection['status'])?></span></div><div class="row g-4"><div class="col-lg-5"><div class="card shadow-sm"><div class="card-body"><h2 class="h5">Connection</h2><dl class="row mb-3"><dt class="col-5">Configured</dt><dd class="col-7"><?=$configured?'Yes':'No'?></dd><dt class="col-5">Realm ID</dt><dd class="col-7"><?=e($connection['realm_id']?:'Not connected')?></dd><dt class="col-5">Last sync</dt><dd class="col-7"><?=e($connection['last_sync_at']?:'Never')?></dd></dl><?php if($connection['status']==='connected'):?><form method="post" action="/portal/quickbooks/disconnect"><?=csrf_field()?><button class="btn btn-outline-danger">Disconnect</button></form><?php else:?><form method="post" action="/portal/quickbooks/connect"><?=csrf_field()?><button class="btn btn-primary" <?=$configured?'':'disabled'?>>Connect QuickBooks</button></form><?php endif?><?php if($connection['last_error']):?><div class="alert alert-danger mt-3"><?=e($connection['last_error'])?></div><?php endif?></div></div></div><div class="col-lg-7"><div class="card shadow-sm"><div class="card-body"><h2 class="h5">Synchronization Log</h2><div class="table-responsive"><table class="table"><thead><tr><th>Time</th><th>Entity</th><th>Direction</th><th>Status</th><th>Message</th></tr></thead><tbody><?php foreach($logs as $l):?><tr><td><?=e($l['created_at'])?></td><td><?=e($l['entity_type'].' #'.$l['entity_id'])?></td><td><?=e($l['direction'])?></td><td><?=e($l['status'])?></td><td><?=e($l['message'])?></td></tr><?php endforeach?></tbody></table></div></div></div></div></div>
